mapper.select:
SELECT id, wallet_id, type, amount, balance_after, pg_transaction_id, status, reference_id, created_at, updated_at, processing_token
FROM cash_transactions
WHERE id = #{id}

mapper.update:
UPDATE cash_transactions
SET status = 'FAILED',
    updated_at = now()
WHERE id = #{id}
  AND status = 'PROCESSING'
  AND processing_token = #{processingToken}

UPDATE cash_transactions
SET processing_token = #{newToken},
    updated_at = now()
WHERE id = #{id}
  AND status = 'PROCESSING'
  AND processing_token = #{expectedToken}

mapper.select:
SELECT id, wallet_id, type, amount, balance_after, pg_transaction_id, status, reference_id, created_at, updated_at, processing_token
FROM cash_transactions
WHERE wallet_id = #{walletId}

    AND type = #{type}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM cash_transactions
WHERE wallet_id = #{walletId}

    AND type = #{type}

SELECT EXISTS (
    SELECT 1 FROM cash_transactions
    WHERE wallet_id = #{walletId}
      AND reference_id = #{referenceId}
      AND type IN ('CHALLENGE_PRINCIPAL_SUCCESS', 'CHALLENGE_PRINCIPAL_FAIL')
)

SELECT id, wallet_id, type, amount, balance_after, pg_transaction_id, status, reference_id, created_at, updated_at, processing_token
FROM cash_transactions
WHERE wallet_id = #{walletId}
  AND reference_id = #{referenceId}
  AND type = #{type}
ORDER BY created_at DESC
LIMIT 1
